import{_ as a,o as e,c as i,ag as r}from"./chunks/framework.YaIgwL5o.js";const g=JSON.parse('{"title":"Charts","description":"","frontmatter":{},"headers":[],"relativePath":"features/charts.md","filePath":"features/charts.md"}'),s={name:"features/charts.md"};function l(n,t,o,d,h,c){return e(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="charts" tabindex="-1">Charts <a class="header-anchor" href="#charts" aria-label="Permalink to &quot;Charts&quot;">​</a></h1><p>Slides Editor includes a built-in chart editor powered by <a href="https://www.chartjs.org/" target="_blank" rel="noreferrer">Chart.js</a>, letting you create data visualizations directly on your slides without any external tools.</p><h2 id="inserting-a-chart" tabindex="-1">Inserting a chart <a class="header-anchor" href="#inserting-a-chart" aria-label="Permalink to &quot;Inserting a chart&quot;">​</a></h2><ol><li>Right-click on the slide canvas and choose <strong>Insert → Chart</strong>.</li><li>A chart dialog opens. Select the chart type: <ul><li><strong>Bar</strong> — vertical or horizontal bar chart</li><li><strong>Line</strong> — line chart with optional fill</li><li><strong>Scatter</strong> — X/Y scatter plot with optional trend line</li></ul></li><li>Click <strong>Create</strong>. A default chart is placed on the slide with sample data.</li></ol><h2 id="editing-chart-data" tabindex="-1">Editing chart data <a class="header-anchor" href="#editing-chart-data" aria-label="Permalink to &quot;Editing chart data&quot;">​</a></h2><p>Double-click the chart element to open the <strong>chart data editor</strong>:</p><ul><li>The editor shows a spreadsheet-style grid with columns for labels and data series.</li><li>Click any cell to edit the value.</li><li>Add rows with the <strong>+ Row</strong> button; add series with <strong>+ Series</strong>.</li><li>Delete rows or series with the trash icon.</li><li>Changes are reflected in the live chart preview above the grid.</li></ul><h2 id="chart-styling" tabindex="-1">Chart styling <a class="header-anchor" href="#chart-styling" aria-label="Permalink to &quot;Chart styling&quot;">​</a></h2><p>With the chart selected, the right panel exposes styling options:</p><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Chart title</td><td>Optional title shown above the chart</td></tr><tr><td>Legend</td><td>Toggle on/off; position (top, bottom, left, right)</td></tr><tr><td>Colors</td><td>Set a color for each data series</td></tr><tr><td>Bar/line width</td><td>Stroke width for line charts</td></tr><tr><td>Fill</td><td>Fill area under line charts</td></tr><tr><td>Grid lines</td><td>Toggle X and Y grid lines</td></tr><tr><td>Axis labels</td><td>Custom labels for X and Y axes</td></tr><tr><td>Font size</td><td>Global font size for labels and title</td></tr></tbody></table><h2 id="resizing-and-positioning" tabindex="-1">Resizing and positioning <a class="header-anchor" href="#resizing-and-positioning" aria-label="Permalink to &quot;Resizing and positioning&quot;">​</a></h2><p>Resize and move the chart element like any other element — drag to reposition, drag corners to scale.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For publication-quality charts, consider exporting your data visualization from a dedicated tool (matplotlib, R ggplot2) and inserting it as an image. The built-in chart editor is best for quick, editable in-slide charts.</p></div><h2 id="example-data-format" tabindex="-1">Example data format <a class="header-anchor" href="#example-data-format" aria-label="Permalink to &quot;Example data format&quot;">​</a></h2><p>If you paste data from a spreadsheet, use tab-separated values:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Label   Series 1   Series 2</span></span>
<span class="line"><span>Q1      42         35</span></span>
<span class="line"><span>Q2      58         47</span></span>
<span class="line"><span>Q3      63         52</span></span>
<span class="line"><span>Q4      71         60</span></span></code></pre></div><p>Paste this directly into the data grid, and Slides Editor will parse the labels and series automatically.</p>`,17)])])}const u=a(s,[["render",l]]);export{g as __pageData,u as default};
